final:
module RefModule(
    input [7:0] d0, d1, d2, d3,
    input s0, s1,
    output [7:0] out
);wire [1:0] desel;
assign desel = {s1, s0};

assign out = (desel == 2'b00) ? d0 :
             (desel == 2'b01) ? d1 :
             (desel == 2'b10) ? d2 :
             (desel == 2'b11) ? d3 : 8'b0;

endmodule
